/// <summary>
/// Form class <c>ETGSPAINUnsoldJournal</c> for handling the Unsold Journal process in the ETGSPAIN module.
/// This form manages both source and target inventory dimensions and ensures that only unposted records are editable or deletable.
/// </summary>
[Form]
public class ETGSPAINUnsoldJournal extends FormRun
{   
    InventDimCtrl_Frm_EditDimensions inventDimFormSetup;
    InventDimIssueReceiptFormBuilder    inventDimIssueReceiptFormBuilder;

}

/// <summary>
/// Initializes the form.
/// This method is used to set up the form when it is loaded.
/// </summary>
public void init()
{
    super();        
}

/// <summary>
/// Adds dimension fields to the grid for managing inventory dimensions.
/// </summary>
private void addDimensionFieldsToGrid()
{
    inventDimIssueReceiptFormBuilder = InventDimIssueReceiptFormBuilder::newFromParameters(
        this.form().design().control(formControlStr(ETGSPAINUnsoldJournal, DimensionsGroup)),
        this.form().dataSource(formDataSourceStr(ETGSPAINUnsoldJournal, InventDim)),
        this.form().dataSource(formDataSourceStr(ETGSPAINUnsoldJournal, ToInventDim)));

    inventDimIssueReceiptFormBuilder.build();
}

/// <summary>
/// Manages the behavior of the data source when records are active, such as enabling or disabling fields based on the posting status.
/// </summary>
public int active()
{
    int ret;

    ret = super();

    ETGSPAINUnsoldJournalTable_DS.allowEdit(ETGSPAINUnsoldJournalTable.Posted   == NoYes::No);
    ETGSPAINUnsoldJournalTable_DS.allowDelete(ETGSPAINUnsoldJournalTable.Posted == NoYes::No);

    ETGSPAINUnsoldJournalCheckPostController.enabled(ETGSPAINUnsoldJournalTable.RecId && ETGSPAINUnsoldJournalTable.Posted == NoYes::No);
    ETGSPAINUnsoldJournalImportLogController.enabled(ETGSPAINUnsoldJournalTable.RecId && ETGSPAINUnsoldJournalTable.Posted == NoYes::No);
    ETGSPAINUnsoldJournalImportLogTable.enabled(ETGSPAINUnsoldJournalTable.hasETGSPAINUnsoldJournalImportLogTable());

    ETGSPAINUnsoldJournalTrans_DS.allowCreate(ETGSPAINUnsoldJournalTable.Posted == NoYes::No);
    ETGSPAINUnsoldJournalTrans_DS.allowEdit(ETGSPAINUnsoldJournalTable.Posted   == NoYes::No);
    ETGSPAINUnsoldJournalTrans_DS.allowDelete(ETGSPAINUnsoldJournalTable.Posted == NoYes::No);

    InventDim_DS.allowCreate(ETGSPAINUnsoldJournalTable.Posted == NoYes::No);
    InventDim_DS.allowEdit(ETGSPAINUnsoldJournalTable.Posted   == NoYes::No);
    ToInventDim_DS.allowCreate(ETGSPAINUnsoldJournalTable.Posted == NoYes::No);
    ToInventDim_DS.allowEdit(ETGSPAINUnsoldJournalTable.Posted   == NoYes::No);

    return ret;
}

/// <summary>
/// Initializes the transaction record from the Unsold Journal table.
/// </summary>
public void initValue()
{
    super();

    ETGSPAINUnsoldJournalTrans.initFromETGSPAINUnsoldJournalTable(ETGSPAINUnsoldJournalTable);
}

/// <summary>
/// Validates and writes the inventory dimension and transaction data before saving the record.
/// </summary>
public boolean validateWrite()
{
    boolean ret;

    ETGSPAINUnsoldJournalTrans.InventDimId = InventDim::findOrCreate(InventDim_ds.cursor()).InventDimId;
    ETGSPAINUnsoldJournalTrans.ToInventDimId = InventDim::findOrCreate(ToInventDim_ds.cursor()).InventDimId;

    ret = super();

    return ret;
}

/// <summary>
/// Validates and writes the inventory dimension for the current record.
/// </summary>
public boolean validateWrite()
{
    boolean ret;

    ret = super();

    ETGSPAINUnsoldJournalTrans.InventDimId = InventDim::findOrCreate(InventDim_ds.cursor()).InventDimId;
    ETGSPAINUnsoldJournalTrans.write();

    return ret;
}

/// <summary>
/// Initializes the destination inventory dimension link for transactions.
/// </summary>
void init()
{
    QueryBuildDataSource qb;

    super();

    qb = this.query().dataSourceName("ToInventDim");
    qb.clearLinks();
    qb.addLink(fieldNum(ETGSPAINUnsoldJournalTrans, ToInventDimId),fieldNum(InventDim,InventDimId));
}

/// <summary>
/// Validates and writes the destination inventory dimension for the current record.
/// </summary>
public boolean validateWrite()
{
    boolean ret;

    ret = super();

    ETGSPAINUnsoldJournalTrans.ToInventDimId = InventDim::findOrCreate(ToInventDim_ds.cursor()).InventDimId;
    ETGSPAINUnsoldJournalTrans.write();

    return ret;
}
